import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"77. Examination Leave","description":"","frontmatter":{"title":"77. Examination Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/nurses-midwives/education-pd/77-examination-leave.md","filePath":"ebas/nurses-midwives/education-pd/77-examination-leave.md"}'),i={name:"ebas/nurses-midwives/education-pd/77-examination-leave.md"};function s(r,e,l,p,m,d){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_77-examination-leave" tabindex="-1">77. Examination Leave <a class="header-anchor" href="#_77-examination-leave" aria-label="Permalink to &quot;77. Examination Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p><strong>77.1</strong> Where examination leave is available</p><p>Examination leave is for undertaking and/or preparing for examinations in a course of study. Examinations include major assessment tasks, take home exams and other methods of student assessment.</p><p><strong>77.2</strong> Examination leave</p><p>Employees who meet the criteria in this clause are entitled to five days paid examination leave per year. Leave entitlements pursuant to this clause will not accumulate from year to year.</p><p><strong>77.3</strong> Employee eligibility</p><p>To be eligible for examination leave, an Employee must:</p><p><strong>(a)</strong> be employed to work, on average, at least three shifts or 24 hours per week; and</p><p><strong>(b)</strong> have been employed for not less than eighteen (18) months by their current Employer immediately prior to taking of examination leave.</p><p><strong>77.4</strong> Eligible course of study</p><p><strong>(a)</strong> To be eligible for examination leave, the course of study must be:</p><p><strong>(i)</strong> related to the Employee&#39;s Classification in Grades duty requirements; and</p><p><strong>(ii)</strong> relevant to advancement through the career structure and to employment at the establishment.</p><p><strong>(b)</strong> Such a course of study would normally be undertaken in a tertiary institution.</p><p><strong>77.5</strong> Time of taking leave</p><p>Examination leave will be taken at a time that is agreed between the Employer and the Employee. The Employer will not unreasonably withhold approval for such leave.</p><p><strong>77.6</strong> Payment</p><p>A day for the purposes of examination leave is the Employee&#39;s normal shift length.</p><p>Plain language terms: exam leave, test leave.</p>',20)])])}const g=a(i,[["render",s]]);export{h as __pageData,g as default};
